INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('pp_probe_and_sheet_arrows_camouflaged_by_translucent_plate_blend', 'Probe arrows / sheet-field arrows / field lines / test-charge force arrow in parallel_plates camouflage into a muddy plate-color blend instead of reading on top of the translucent +/- plates', 'MAJOR', 'peter_parker:renderer_primitives', 'buildParallelPlatesField() never applied depthTest:false + high renderOrder to its probe_arrows, sheet_fields, field_lines, fringe, or test_charge/force-arrow primitive groups — the exact same "reads through a translucent shell" situation gauss_law_sphere/line/sheet already solve elsewhere in this file (gsphMakeThickVector ~22219, gln cap-graze arrows ~23805, gsph_inside_probe ~22409). Two of the three STATE_2 probe arrows (near +/- plate) sit close to or inside the translucent plate slab in z, and without the fix the default THREE.js transparent depthTest/depthWrite ordering blends the plate alpha over the arrow, producing a muddy tan/gold that is visually indistinguishable from the background field lines — destroying the PRIMARY aha (three IDENTICAL probe arrows proving uniform field). The same mechanism produced a mid-shaft color-split on the field lines during the STATE_5 gap-widen sweep.', 'Any field_3d arrow/line/probe primitive that is authored to sit at, near, or inside a translucent shell/plate/sheet mesh MUST get depthTest:false + depthWrite:false + a high renderOrder (>= 998, above the shell/plate default of 0) at construction time — never rely on THREE.js default transparent-object depth sorting to get the visual layering right. Apply this at the shared arrow-building helper (platesArrowGroup here) so every caller inherits it, not per call-site.', 'manual', 'STATE_2 of parallel_plate_capacitor_field: sample RGB at all 3 probe-arrow positions in the frozen frame — all 3 must match the authored #66BB6A (within tolerance) and match each other; a connected-component scan of the green mask must show pixels spread across the FULL plate width (not clustered in one narrow region); a scan for the 50/50 plate-color/#66BB6A blend RGB must return 0 matches anywhere in the frame. Repeat the blend-color scan across the STATE_5 gap-widen dense frames (t00000..t24000) — 0 matches at every sampled frame confirms no mid-shaft color-split.', 'FIXED', ARRAY['parallel_plate_capacitor_field'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-07-08_ppc_state2_probe_arrow_camouflage_fix', 'incident')
